const query = $json.body.query || '';
const id = $json.body.id || '';
const mode = ($json.body.mode || 'OR').toUpperCase();

let finalQuery = {};
let isIdSearch = false; // ID 검색 여부를 판단하는 플래그

// 1. ID가 존재하는 경우
if (id) {
  // ID 검색 쿼리 객체 생성
  // MongoDB Extended JSON 형식의 "$oid"를 사용
  finalQuery = { _id: { "$oid": id } };
  isIdSearch = true;
} 
// 2. ID가 없고 키워드가 존재하는 경우 (기존 로직)
else if (query.trim().length > 0) {
  const keywords = query
    .split(' ')
    .map(k => k.trim())
    .filter(k => k.length > 0);

  const fields = [
    'originalName',
    'ocr.full_text',
    'ocr.summary',
    'meta.filename'
  ];

  const buildSingleKeywordQuery = (keyword) =>
    fields.map(field => ({ [field]: { $regex: keyword, $options: 'i' } }));

  if (mode === 'AND') {
    finalQuery = {
      $and: keywords.map(kw => ({ $or: buildSingleKeywordQuery(kw) }))
    };
  } else {
    finalQuery = {
      $or: keywords.flatMap(kw => buildSingleKeywordQuery(kw))
    };
  }
}
// 3. ID도 없고 키워드도 없는 경우
else {
  return [{ json: {} }];
}


// 다음 노드로 쿼리와 플래그를 함께 전달
return [{
  json: {
    query: finalQuery,
    isIdSearch: isIdSearch
  }
}];

// Stringify Mongo Query 노드 수정 코드
const input = $json;
const mongoQuery = input.query;
const isIdSearch = input.isIdSearch;

let outputJson;

if (isIdSearch) {
  // ID 검색일 경우, _id 필드만 남기고 JSON 객체로 반환
  outputJson = {
    _id: mongoQuery._id["$oid"]
  };
} else {
  // 키워드 검색일 경우, 쿼리 객체 그대로 반환
  outputJson = mongoQuery;
}

return [
  {
    json: {
      mongoQuery: JSON.stringify(outputJson)
    }
  }
];
